+class OverriddenMethodHasNonNullableArgAndRetType {
+    class Test {
+        String! m(String! s) { return ""; }
+    }
+    class Sub extends Test {
+        @Override
+        String m(String s) { return null; }
+    }
+    interface I {
+        void m(String! s);
+    }
+    I i = (String s) -> {};
+
+    interface MathFunc {
+        Integer operate(Integer! a, Integer! b);
+    }
+
+    class Impl {
+        public Integer add(Integer a, Integer b) {
+            return a + b;
+        }
+    }
+
+    class MethRefTest {
+        void m(Impl impl) {
+            MathFunc mathFunc = impl::add;
+        }
+    }
+}

